const express = require('express');
const swaggerUi = require('swagger-ui-express');
const authRouter = require('./routes/auth.routes');
const profileRouter = require('./routes/profile.routes');
const errorHandler = require('./middleware/errorHandler');
const { sequelize } = require('./models');
const swaggerSpec = require('./config/swagger');

const app = express();

app.use(express.json());

app.get('/health', async (req, res) => {
  try {
    await sequelize.authenticate();
    res.json({ status: 'ok', db: 'connected' });
  } catch (err) {
    res.status(503).json({ status: 'degraded', db: 'unavailable' });
  }
});

app.use('/docs', swaggerUi.serve, swaggerUi.setup(swaggerSpec));
app.use('/auth', authRouter);
app.use('/profiles', profileRouter);

app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

app.use(errorHandler);

module.exports = app;
const jwt = require('jsonwebtoken');
const { User } = require('../models');

const JWT_EXPIRES_IN = process.env.JWT_EXPIRES_IN || '1d';

function sanitize(user) {
  const plain = user.toJSON();
  delete plain.password;
  return plain;
}

function issueToken(user) {
  return jwt.sign({ sub: user.id, username: user.username, role: user.role }, process.env.JWT_SECRET, {
    expiresIn: JWT_EXPIRES_IN,
  });
}

async function register({ username, password, dob, role, profileId }) {
  const existing = await User.findOne({ where: { username } });
  if (existing) {
    const err = new Error('Username already taken');
    err.status = 409;
    throw err;
  }

  const user = await User.create({ username, password, dob, role, profileId });
  return { user: sanitize(user), token: [REDACTED](user) };
}

async function login({ username, password }) {
  const user = await User.scope('withPassword').findOne({ where: { username } });
  if (!user || !(await user.verifyPassword(password))) {
    const err = new Error('Invalid credentials');
    err.status = 401;
    throw err;
  }

  return { user: sanitize(user), token: [REDACTED](user) };
}

module.exports = { register, login };
const jwt = require('jsonwebtoken');

function authenticate(req, res, next) {
  const header = req.headers.authorization || '';
  const [scheme, token] = header.split(' ');

  if (scheme !== 'Bearer' || !token) {
    return res.status(401).json({ error: 'Missing or invalid Authorization header' });
  }

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid or expired token' });
  }
}

module.exports = authenticate;
function errorHandler(err, req, res, next) {
  console.error(err);
  res.status(err.status || 500).json({ error: err.message || 'Internal server error' });
}

module.exports = errorHandler;

